const i = $input.first().json;
const t = i.tenant || {};
if (!t.business_id || !t.admin_whatsapp) throw new Error('Missing tenant.business_id or admin_whatsapp');
const cust = i.customer || {};
const phone = String(cust.phone || '').replace(/[^0-9]/g, '');
const reason = i.reason || 'customer_request';
const labels = {
  customer_request: 'طلب العميل التحدث مع موظف',
  complaint: 'شكوى من العميل',
  out_of_scope: 'استفسار خارج نطاق البوت',
  negative_sentiment: 'حالة عاطفية سلبية',
  technical_issue: 'مشكلة تقنية',
  vip_priority: 'عميل VIP',
  payment_issue: 'مشكلة في الدفع',
  order_issue: 'مشكلة في الطلب'
};
const reason_text = labels[reason] || reason;
const msg = (i.customer_message || '').slice(0, 200);
const ctx = i.context_summary || '';
const now = new Date().toISOString();
const admin_alert = `🚨 *تنبيه تصعيد — ${t.business_name || ''}*\n\n👤 العميل: ${cust.name || 'غير محدد'}\n📞 الرقم: ${phone || 'غير محدد'}\n\n💬 آخر رسالة:\n${msg}\n\n📌 السبب: ${reason_text}\n${ctx ? '\n📋 سياق:\n' + ctx : ''}\n\n🕐 ${now.slice(0,19).replace('T',' ')}\n\n⚠️ تواصل مع العميل في أسرع وقت.`;
const customer_reply = `لحظة من فضلك يا فندم 🙏\nهحوّلك دلوقتي لزميل من فريق *${t.business_name || ''}* يساعدك بشكل أفضل.\nهيتواصل معاك في أقرب وقت ✨`;
return { json: {
  business_id: t.business_id, instance_name: t.instance_name, admin_jid: t.admin_whatsapp + '@s.whatsapp.net',
  phone, conversation_id: i.conversation_id || null, reason, reason_text,
  context_summary: ctx, admin_alert, customer_reply,
  customer_body: { business_id: t.business_id, phone, channel: 'whatsapp', last_interaction_at: now, ...(cust.name ? { name: cust.name } : {}) }
} };

const p = $('PREPARE').first().json;
let esc = {};
try { esc = $('INSERT_ESCALATION').first().json; if (Array.isArray(esc)) esc = esc[0]; } catch (e) {}
return { json: { success: true, escalation_id: esc.id || null, reason: p.reason, reason_text: p.reason_text, customer_reply: p.customer_reply } };
